{
var src = inputs.Length > 0 ? inputs[0] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var amplitude = GetFloat(parameters, "amplitude", 10f);
var frequency = GetFloat(parameters, "frequency", 10f);
var speed = GetFloat(parameters, "speed", 0f);
var direction = GetChoice(parameters, "direction", "horizontal");

var size = src.Width;
var result = new PixelBuffer(size, size);
var phase = speed * (float)(Environment.TickCount % 100000) * 0.001f;

result.ParallelForEachPixel((x, y) =>
{
    var nx = x / (float)size;
    var ny = y / (float)size;
    var dx = 0f;
    var dy = 0f;

    switch (direction)
    {
        case "vertical":
            dy = MathF.Sin(ny * frequency * MathF.Tau + phase) * amplitude;
            break;
        case "both":
            dx = MathF.Sin(ny * frequency * MathF.Tau + phase) * amplitude;
            dy = MathF.Sin(nx * frequency * MathF.Tau + phase) * amplitude;
            break;
        default: // horizontal
            dx = MathF.Sin(ny * frequency * MathF.Tau + phase) * amplitude;
            break;
    }

    var sx = x + dx;
    var sy = y + dy;

    var (r, g, b, a) = src.GetPixelWrapped((int)MathF.Round(sx), (int)MathF.Round(sy));
    result.SetPixel(x, y, r, g, b, a);
});

return result;
}
